def valid_date(date):
    # Rule 1: The date string is not empty
    if not date:
        return False

    # Check if the format is mm-dd-yyyy (exactly two dashes)
    parts = date.split('-')
    if len(parts) != 3:
        return False

    mm, dd, yyyy = parts

    # Check if all parts are numeric
    if not (mm.isdigit() and dd.isdigit() and yyyy.isdigit()):
        return False

    # Convert to integers
    try:
        month = int(mm)
        day = int(dd)
        year = int(yyyy)
    except ValueError:
        return False

    # Rule 3: The months should not be less than 1 or higher than 12
    if month < 1 or month > 12:
        return False

    # Rule 2: Validate days based on month
    # Months with 31 days: 1,3,5,7,8,10,12
    if month in [1, 3, 5, 7, 8, 10, 12]:
        if day < 1 or day > 31:
            return False
    # Months with 30 days: 4,6,9,11
    elif month in [4, 6, 9, 11]:
        if day < 1 or day > 30:
            return False
    # Month 2 (February): max 29 days as per problem statement
    elif month == 2:
        if day < 1 or day > 29:
            return False

    # Additional check: verify the format is exactly mm-dd-yyyy (no leading zeros issues)
    # Check if the string matches the expected format (two digits for mm and dd, four for yyyy)
    if len(mm) != 2 or len(dd) != 2 or len(yyyy) != 4:
        return False

    return True
```

