def valid_date(date):
    # Rule 1: The date string is not empty
    if not date:
        return False

    # Check if the format is mm-dd-yyyy (exactly two dashes)
    parts = date.split('-')
    if len(parts) != 3:
        return False

    mm, dd, yyyy = parts

    # Check if each part consists only of digits
    if not (mm.isdigit() and dd.isdigit() and yyyy.isdigit()):
        return False

    # Convert to integers
    try:
        month = int(mm)
        day = int(dd)
        year = int(yyyy)
    except ValueError:
        return False

    # Rule 3: The months should not be less than 1 or higher than 12
    if month < 1 or month > 12:
        return False

    # Rule 2: Validate days based on month
    if month in [1, 3, 5, 7, 8, 10, 12]:
        # Months with 31 days
        if day < 1 or day > 31:
            return False
    elif month in [4, 6, 9, 11]:
        # Months with 30 days
        if day < 1 or day > 30:
            return False
    elif month == 2:
        # February - up to 29 days (as per problem statement)
        if day < 1 or day > 29:
            return False

    # Additional check: ensure proper formatting (two digits for mm and dd, four digits for yyyy)
    # The problem doesn't explicitly require leading zeros, but the examples show them
    # However, the requirement is about the format "mm-dd-yyyy", which implies two-digit month and day
    # But since the examples include '03-11-2000' and '06-04-2020', and '15-01-2012' is invalid due to month=15,
    # we don't need to enforce exactly 2 digits for mm/dd as the numeric validation already catches invalid values

    return True
```

```python
def closest_integer(value):
    num = float(value)

    # Get the integer part and fractional part
    integer_part = int(num)
    fractional_part = abs(num - integer_part)

    # If fractional part is exactly 0.5, round away from zero
    if fractional_part == 0.5:
        if num > 0:
            return integer_part + 1
        else:
            return integer_part - 1
    else:
        # Use built-in round() which rounds to nearest even for .5 cases,
        # but we need away from zero, so handle .5 separately above
        return round(num)
```

```python
def closest_integer(value):
    num = float(value)

    # Get the integer part and fractional part
    integer_part = int(num)
    fractional_part = abs(num - integer_part)

    # If fractional part is less than 0.5, round toward zero
    if fractional_part < 0.5:
        return integer_part

    # If fractional part is greater than 0.5, round away from zero
    if fractional_part > 0.5:
        if num >= 0:
            return integer_part + 1
        else:
            return integer_part - 1

    # If fractional part is exactly 0.5, round away from zero
    if num >= 0:
        return integer_part + 1
    else:
        return integer_part - 1
```

