```python
def digitSum(s):
    total = 0
    for char in s:
        if char.isupper():
            total += ord(char)
    return total
```

```python
def find_max(words):
    if not words:
        return ""

    max_unique_count = 0
    candidates = []

    # Find the maximum number of unique characters
    for word in words:
        unique_count = len(set(word))
        if unique_count > max_unique_count:
            max_unique_count = unique_count
            candidates = [word]
        elif unique_count == max_unique_count:
            candidates.append(word)

    # Return the lexicographically smallest among candidates
    return min(candidates)
```

