def generate_integers(a, b):
    # Determine the range boundaries
    start = min(a, b)
    end = max(a, b)

    # Find even digits (0-9 that are even) in the range
    result = []
    for num in range(start, end + 1):
        # Check if the number is a single digit (0-9) and even
        if 0 <= num <= 9 and num % 2 == 0:
            result.append(num)

    return result
```

