```python
def monotonic(l: list) -> bool:
    if len(l) <= 2:
        return True

    # Check if monotonically increasing
    increasing = True
    for i in range(1, len(l)):
        if l[i] < l[i-1]:
            increasing = False
            break

    # Check if monotonically decreasing
    decreasing = True
    for i in range(1, len(l)):
        if l[i] > l[i-1]:
            decreasing = False
            break

    return increasing or decreasing
```

```python
def fix_spaces(text):
    result = []
    i = 0
    while i < len(text):
        if text[i] == ' ':
            # Count consecutive spaces
            space_count = 0
            j = i
            while j < len(text) and text[j] == ' ':
                space_count += 1
                j += 1

            # Replace based on count
            if space_count > 2:
                result.append('-')
            else:
                result.append('_' * space_count)

            i = j  # Skip all the spaces we just processed
        else:
            result.append(text[i])
            i += 1

    return ''.join(result)
```

```python
def correct_bracketing(brackets: str) -> bool:
    count = 0
    for bracket in brackets:
        if bracket == '<':
            count += 1
        elif bracket == '>':
            count -= 1
        # If count goes negative, we have more closing than opening brackets at some point
        if count < 0:
            return False
    # All brackets must be matched (count should be 0)
    return count == 0
```

