def iscube(a):
    # Handle negative numbers by checking the cube root of absolute value
    # and then checking the sign
    if a < 0:
        # For negative numbers, we need to find if there's a negative integer whose cube is a
        # So we check if |a| is a perfect cube, then verify the sign
        abs_a = abs(a)
        # Find approximate cube root
        cube_root = round(abs_a ** (1/3))
        # Check nearby integers since floating point might be imprecise
        for candidate in [cube_root - 1, cube_root, cube_root + 1]:
            if candidate >= 0 and candidate ** 3 == abs_a:
                return candidate ** 3 == abs_a and (-candidate) ** 3 == a
        return False
    else:
        # For non-negative numbers
        if a == 0:
            return True
        # Find approximate cube root
        cube_root = round(a ** (1/3))
        # Check nearby integers to handle floating point precision issues
        for candidate in [cube_root - 1, cube_root, cube_root + 1]:
            if candidate >= 0 and candidate ** 3 == a:
                return True
        return False
