            if candidate**3 == a:
                return True
            if candidate**3 < a:  # since candidate is negative, smaller candidate gives smaller cube
                break
        return False
```

Actually, let's use a cleaner approach with binary search or direct computation:

```python
def iscube(a):
    if a == 0:
        return True

    # Determine sign and work with absolute value
    sign = 1 if a > 0 else -1
    abs_a = abs(a)

    # Find integer cube root using binary search or direct calculation
    # Since cube root of abs_a is at most abs_a, but we can use a better bound
    if abs_a == 1:
        return True

    # Estimate cube root
    # For large numbers, cube root is roughly abs_a^(1/3)
    # Use rounding and check nearby values
    cube_root = round(abs_a ** (1/3))

    # Check a small range around the estimate
    for candidate in range(max(0, cube_root-2), cube_root+3):
        if candidate**3 == abs_a:
            return True if sign == 1 else candidate == 0 or (candidate > 0 and (-candidate)**3 == a)

    # Check negative candidates for negative a
    if a < 0:
        for candidate in range(-cube_root-2, -cube_root+3):
            if candidate <= 0 and candidate**3 == a:
                return True

    return False
```

Let me write the cleanest version:

```python
def iscube(a):
    if a == 0:
        return True

    # For positive a, check positive cube roots
    # For negative a, check negative cube roots
    if a > 0:
        # Find approximate cube root
        cube_root = round(a ** (1/3))
        # Check integers around the approximation
        for candidate in [cube_root-1, cube_root, cube_root+1]:
            if candidate >= 0 and candidate**3 == a:
                return True
        return False
    else:  # a < 0
        abs_a = abs(a)
        cube_root = round(abs_a ** (1/3))
        # Check negative candidates
        for candidate in [-cube_root-1, -cube_root, -cube_root+1]:
            if candidate <= 0 and candidate**3 == a:
                return True
        return False
```

```python
def remove_vowels(text):
    vowels = "aeiouAEIOU"
    result = ""
    for char in text:
        if char not in vowels:
            result += char
    return result
```
